const e=[{id:"9849a76b-341f-4823-a345-962fda3ced64",category_id:"computer-awareness",tags:["Era Of Computer"],difficulty:"easy",question:"Which of the following refers to too much electricity and may cause a voltage surge?",correctId:"c",options:[{id:"a",text:"Anomaly",label:"A"},{id:"b",text:"Shock",label:"B"},{id:"c",text:"Spike",label:"C"},{id:"d",text:"Virus",label:"D"},{id:"e",text:"Splash",label:"E"}],explanation:'A <span class="text-red" style="font-weight: 800;">voltage spike (or surge) </span>is a brief but intense <span class="text-teal" style="font-weight: 800;">increase in electrical voltage</span>. These sudden, high-energy events can damage electronic equipment and are often caused by factors like lightning strikes or power grid fluctuations. <span class="text-magenta" style="font-weight: 800;">Surge protectors</span> are used to mitigate their impact.',pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"4b818e9a-e5a2-4a9a-a65e-5425ada4d517",category_id:"computer-awareness",tags:["Memory"],difficulty:"easy",question:"Which of the following is a secondary memory device?",correctId:"a",options:[{id:"a",text:"Disk",label:"A"},{id:"b",text:"Keyboard",label:"B"},{id:"c",text:"ALU",label:"C"},{id:"d",text:"All of the above",label:"D"},{id:"e",text:"None of these",label:"E"}],explanation:'<span class="text-red" style="font-weight: 800;">Secondary memory devices</span> are used for<span class="text-green" style="font-weight: 800;"> long-term storage</span> of data and programs, even when the computer is turned off. A disk (like a Hard Disk Drive or Solid State Drive) is a prime example. A keyboard is an input device, and an ALU is part of the CPU.',pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"d8375c6e-537e-44a8-bae2-bf34c5426dec",category_id:"computer-awareness",tags:["Era Of Computer"],difficulty:"easy",question:"Travel agents use this computer system when reserving flights.",correctId:"c",options:[{id:"a",text:"Supercomputer",label:"A"},{id:"b",text:"Mainframe computer",label:"B"},{id:"c",text:"Personal computer",label:"C"},{id:"d",text:"All of the above",label:"D"},{id:"e",text:"None of these",label:"E"}],explanation:"Travel agents primarily use personal computers (PCs) to access and operate various booking systems for flights, hotels, and other travel services. These systems are often connected to larger databases, which may reside on mainframe computers or servers, but the agent's interface is typically a PC.",pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"2197fb53-8df5-482e-b636-2a306a67057a",category_id:"computer-awareness",tags:["Software"],difficulty:"medium",question:"The language that the computer can understand and execute is called",correctId:"b",options:[{id:"a",text:"Application software",label:"A"},{id:"b",text:"Machine language",label:"B"},{id:"c",text:"System program",label:"C"},{id:"d",text:"All of the above",label:"D"},{id:"e",text:"None of these",label:"E"}],explanation:`Machine language, also known as <span class="text-green" style="font-weight: 800;">machine code</span>, is the<span class="text-teal" style="font-weight: 800;"> lowest-level programming language</span> directly understood and executed by a computer's CPU. It consists of<span class="text-green" style="font-weight: 800;"> binary instructions</span> (sequences of 0s and 1s). &amp;_Hardware`,pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"a1355059-043f-4623-8ef8-79b5a7aaa16d",category_id:"computer-awareness",tags:["Era Of Computer"],difficulty:"medium",question:"Speed of first generation computer was in",correctId:"b",options:[{id:"a",text:"nano seconds",label:"A"},{id:"b",text:"milli seconds",label:"B"},{id:"c",text:"nano-milli seconds",label:"C"},{id:"d",text:"micro seconds",label:"D"},{id:"e",text:"None of these",label:"E"}],explanation:'The <span class="text-blue" style="font-weight: 800;">first generation computers</span>, which used <span class="text-green" style="font-weight: 800;">vacuum tubes</span>, were characterized by their relatively <span class="text-teal" style="font-weight: 800;">slow processing speeds</span>, typically measured <span class="text-green" style="font-weight: 800;">in milliseconds</span>. Subsequent generations saw speeds increase to microseconds, then nanoseconds, and now picoseconds.',pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"99833abf-9467-44bc-b402-aa3895b577d8",category_id:"computer-awareness",tags:["Memory","Era Of Computer"],difficulty:"easy",question:"Where would you find a magnetic strip?",correctId:"b",options:[{id:"a",text:"Speakers",label:"A"},{id:"b",text:"Credit card",label:"B"},{id:"c",text:"Smart card",label:"C"},{id:"d",text:"All of the above",label:"D"},{id:"e",text:"None of these",label:"E"}],explanation:`A <span class="text-red" style="font-weight: 800;">magnetic strip</span> is commonly found on the back of <span class="text-teal" style="font-weight: 800;">credit cards, driver's licenses, and other ID</span> cards to<span class="text-green" style="font-weight: 800;"> store data</span>. <div><span class="text-red" style="font-weight: 800;">Smart cards</span> typically use an<span class="text-teal" style="font-weight: 800;"> embedded microchip for data storage</span>, not just a magnetic strip.  </div>`,pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"},{id:"5dbb91ab-ca95-4ade-844b-5cbfddd25805",category_id:"computer-awareness",tags:["Software"],difficulty:"easy",question:"The errors that can be pointed out by the compiler are",correctId:"c",options:[{id:"a",text:"Logical errors",label:"A"},{id:"b",text:"Semantic errors",label:"B"},{id:"c",text:"Syntax errors",label:"C"},{id:"d",text:"None of the above",label:"D"}],explanation:`<span class="text-red" style="font-weight: 800;">Compilers</span> are designed to<span class="text-magenta" style="font-weight: 800;"> detect syntax errors</span>, which are <span style="font-style: italic;">violations of the programming language's rules regarding structure and grammar</span>. <span class="text-red" style="font-weight: 800;">Logical errors and semantic errors</span>, pertaining to <span class="text-orange" style="font-weight: 800;">program behavior and meaning,</span> are generally harder for compilers to identify and are found during runtime or testing.  &amp;_Hardware`,pyq:null,created_at:"2026-06-14T15:41:33.499294+00:00"}];export{e as default};
